static int resolve_path(int dfd, const char __user* filename, int flags, 
    struct path *path)
{
  int lookup_flags = LOOKUP_FOLLOW;

  if (flags & AT_EMPTY_PATH)
    lookup_flags |= LOOKUP_EMPTY;
