static DEFINE_SPINLOCK(ldw_ctl_lock);
static int default_action = LDW_RES_DENY;

static inline void _trim(char *str, const char *testing) {
  int total_len = strlen(str), top_len = strlen(testing);
  if (total_len < top_len)
    return;

