SYSCALL_HOOK3(execve, 
    const char __user*, filename,
    const char __user *const __user *, argv,
    const char __user *const __user *, envp) 
{
  int error;
  struct path fpath;
  error = resolve_path(AT_FDCWD, filename, 0, &fpath);
  if (error < 0)
    HOOK_RET(error);
  return check_file(&fpath);
}

