  if (res < 0)
    return ERR_PTR(res);

  out = kmalloc(PATH_MAX, GFP_KERNEL);
  if (!out)
    return ERR_PTR(-ENOMEM);
  set_delayed_call(clean, (void (*)(void*))kfree, out);

  out = d_path(&pout, out, PATH_MAX);
  if (!IS_ERR(out))
    _trim(out, " (deleted)");

