{
  int len = strnlen_user(u_name, size);
  char *name;

  if (r->name_len < size) {
    name = kmalloc(size, GFP_KERNEL);
    if (!name)
      return -ENOMEM;
    r->name_len = size;
  } else {
    name = r->name;
    BUG_ON(!name);
  }

  if (copy_from_user(name, u_name, size)) {
    kfree(name);
    return -EFAULT;
  }

  if (r->name != name) {
    kfree(r->name);
    r->name = name;
  }

  if (len >= size)
    // Truncate the file name if too long
    name[len - 1] = 0;
  else
    // Otherwise zero out rest of string
    memset(name + len, 0, size - len);

  return 0;
}

