      case LDW_RES_NOMATCH: break;
      case LDW_RES_ALLOW:   goto out;
      case LDW_RES_DENY:    res = -1; goto out;
    }
  }

  if (default_action == LDW_RES_DENY)
    res = -1;
out:
  read_unlock(&ldw_rules_lock);
  return res;
}

